// =============================================================================
// MM SFX System - Direct Audio Bypass
// =============================================================================
// Decodes MM ADPCM samples to PCM and mixes directly into OOT's audio output.
// This bypasses OOT's entire SFX pipeline (which caches sound data at startup
// and cannot play injected samples during gameplay).
//
// Architecture:
//   Game thread: MmSfx_PlayAtPos() → decode ADPCM → add to playing list
//   Audio thread: MmDirectAudio_MixInto() → mix PCM into output buffer
// =============================================================================

// MM SFX ID macros (matching OOT's z64audio.h SFX_INDEX)
#define MM_SFX_BANK_SHIFT 12
#define MM_SFX_INDEX_MASK 0x03FF
#define MM_SFX_BANK_INDEX(sfxId) (((sfxId) >> MM_SFX_BANK_SHIFT) & 0xF)
#define MM_SFX_SOUND_INDEX(sfxId) ((sfxId)&MM_SFX_INDEX_MASK)

// MM Goron SFX IDs
#define MM_NA_SE_PL_GORON_ROLL 0x0990
#define MM_NA_SE_PL_GORON_CHG_ROLL 0x0980
#define MM_NA_SE_PL_GORON_BALL_CHARGE 0x08EB
#define MM_NA_SE_SY_TRANSFORM_MASK_FLASH 0x484F

#define MM_SFX_MAX_FONTS 42 // MM has 41 soundfonts (0-40)
#define MM_SFX_FONT_PATH_FMT "audio/fonts/Soundfont_%d"

// MM SFX sequence (NA_BGM_GENERAL_SFX) uses soundfont 0 as the main SFX font.
// Player/Item/Env/System/Ocarina banks use instruments[]. Voice bank uses soundEffects[] (FONTANY_INSTR_SFX).
// Enemy bank uses Soundfont_1.
static const s32 sMmBankToFontMap[] = { 0, 0, 0, 1, 0, 0, 0 };

// --- Font cache ---
typedef struct {
    s32 fontId;
    SoundFont* font;
    size_t sizeBytes;
} MmSfxCacheEntry;

static MmSfxCacheEntry sSfxCache[MM_SFX_MAX_FONTS];
static s32 sSfxCacheCount = 0;
static s32 sSfxInitialized = 0;
static f32 sTempFreqScale = 1.0f;

static void MmSfxCache_Init(void) {
    if (sSfxInitialized)
        return;
    for (s32 i = 0; i < MM_SFX_MAX_FONTS; i++) {
        sSfxCache[i].fontId = -1;
        sSfxCache[i].font = nullptr;
        sSfxCache[i].sizeBytes = 0;
    }
    sSfxCacheCount = 0;
    sSfxInitialized = 1;
}

static MmSfxCacheEntry* MmSfxCache_Find(s32 fontId) {
    for (s32 i = 0; i < sSfxCacheCount; i++) {
        if (sSfxCache[i].fontId == fontId)
            return &sSfxCache[i];
    }
    return nullptr;
}

static MmSfxCacheEntry* MmSfxCache_GetFree(void) {
    if (sSfxCacheCount < MM_SFX_MAX_FONTS)
        return &sSfxCache[sSfxCacheCount++];
    for (s32 i = 0; i < MM_SFX_MAX_FONTS - 1; i++)
        sSfxCache[i] = sSfxCache[i + 1];
    sSfxCacheCount = MM_SFX_MAX_FONTS - 1;
    return &sSfxCache[sSfxCacheCount++];
}

s32 MmSfx_IsAvailable(void) {
    if (CVarGetInteger("gEnhancements.SkijerNEI.MuteMmAudio", 0)) {
        return 0;
    }
    return MmAssets_IsAvailable();
}

void MmSfx_Init(void) {
    MmSfxCache_Init();
}

void MmSfx_Shutdown(void) {
    MmDirectAudio_StopAll();
    MmSfx_FlushCache();
    sSfxInitialized = 0;
}

// =============================================================================
// Post-load sample patching: Re-resolve all samples from mm.o2r
// =============================================================================
// The AudioSoundFont factory internally calls LoadResourceProcess(sampleFileName) for each
// sample reference. That function uses the global ResourceManager which:
// 1. Checks its cache first (may return OOT samples loaded during OOT audio init)
// 2. Searches archives by priority (mm.o2r is LOWEST = searched last)
// Result: MM soundfont structure with OOT audio sample data = wrong sounds.
//
// This function re-reads the soundfont binary from mm.o2r, extracts sample path strings,
// loads each sample directly from mm.o2r (bypassing ResourceManager cache), and patches
// the SoundFont's sample pointers with the correct MM data.
// =============================================================================

// Minimal binary reader helpers (C-compatible, operates on raw byte buffer)
typedef struct {
    const u8* data;
    size_t size;
    size_t pos;
    u8 bigEndian;
} MmBinReader;

static u32 MmBin_Swap32(u32 v) {
    return (v >> 24) | ((v >> 8) & 0xFF00) | ((v << 8) & 0xFF0000) | (v << 24);
}
static u16 MmBin_Swap16(u16 v) {
    return (u16)((v >> 8) | (v << 8));
}

static s32 MmBin_ReadS32(MmBinReader* r) {
    u32 v;
    memcpy(&v, &r->data[r->pos], 4);
    r->pos += 4;
    return (s32)(r->bigEndian ? MmBin_Swap32(v) : v);
}
static u32 MmBin_ReadU32(MmBinReader* r) {
    u32 v;
    memcpy(&v, &r->data[r->pos], 4);
    r->pos += 4;
    return r->bigEndian ? MmBin_Swap32(v) : v;
}
static u16 MmBin_ReadU16(MmBinReader* r) {
    u16 v;
    memcpy(&v, &r->data[r->pos], 2);
    r->pos += 2;
    return r->bigEndian ? MmBin_Swap16(v) : v;
}
static u8 MmBin_ReadU8(MmBinReader* r) {
    return r->data[r->pos++];
}
static s8 MmBin_ReadS8(MmBinReader* r) {
    return (s8)r->data[r->pos++];
}
static f32 MmBin_ReadF32(MmBinReader* r) {
    u32 v;
    memcpy(&v, &r->data[r->pos], 4);
    r->pos += 4;
    if (r->bigEndian)
        v = MmBin_Swap32(v);
    f32 f;
    memcpy(&f, &v, 4);
    return f;
}
static void MmBin_Skip(MmBinReader* r, size_t n) {
    r->pos += n;
}

// Read length-prefixed string into caller-provided buffer. Returns length.
static s32 MmBin_ReadString(MmBinReader* r, char* buf, size_t bufSize) {
    s32 len = MmBin_ReadS32(r);
    if (len <= 0 || r->pos + (size_t)len > r->size) {
        if (len > 0)
            r->pos += len;
        buf[0] = '\0';
        return 0;
    }
    size_t copyLen = ((size_t)len < bufSize - 1) ? (size_t)len : bufSize - 1;
    memcpy(buf, &r->data[r->pos], copyLen);
    buf[copyLen] = '\0';
    r->pos += len;
    return len;
}

static void MmSfx_PatchFontSamplesFromMmArchive(SoundFont* font, const char* fontPath) {
    if (!font || !sMmArchive)
        return;

    // Load the raw file from mm.o2r
    auto file = sMmArchive->LoadFile(std::string(fontPath));
    if (!file || !file->Buffer || file->Buffer->size() <= 64) {
        MMSFX_LOG("[MmSfx] PatchSamples: could not load raw file for %s", fontPath);
        return;
    }

    // Read byte order from OTR header (byte 0: 0=Little, 1=Big)
    const u8* rawData = (const u8*)file->Buffer->data();

    // Skip OTR header (64 bytes)
    MmBinReader r;
    r.data = rawData + 64;
    r.size = file->Buffer->size() - 64;
    r.pos = 0;
    r.bigEndian = (rawData[0] == 1) ? 1 : 0;

    char samplePath[256];

    // Parse soundfont header (mirroring AudioSoundFontFactory binary V2 format)
    MmBin_ReadS32(&r); // fntIndex
    MmBin_ReadS8(&r);  // medium
    MmBin_ReadS8(&r);  // cachePolicy
    MmBin_ReadU16(&r); // data1
    MmBin_ReadU16(&r); // data2
    MmBin_ReadU16(&r); // data3
    u32 drumCount = MmBin_ReadU32(&r);
    u32 instrumentCount = MmBin_ReadU32(&r);
    u32 soundEffectCount = MmBin_ReadU32(&r);

    MMSFX_LOG("[MmSfx] PatchSamples: parsing %s (drums=%u, inst=%u, sfx=%u)", fontPath, drumCount, instrumentCount,
              soundEffectCount);

    s32 patchedCount = 0;

    // Parse drums
    for (u32 i = 0; i < drumCount && r.pos < r.size; i++) {
        MmBin_ReadU8(&r); // releaseRate
        MmBin_ReadU8(&r); // pan
        MmBin_ReadU8(&r); // loaded

        u32 envCount = MmBin_ReadU32(&r);
        MmBin_Skip(&r, envCount * 4); // skip envelopes

        MmBin_ReadS8(&r); // hasSample
        MmBin_ReadString(&r, samplePath, sizeof(samplePath));
        MmBin_ReadF32(&r); // tuning

        if (samplePath[0] && font->drums && i < font->numDrums && font->drums[i]) {
            SoundFontSample* mmSample = (SoundFontSample*)MmAssets_LoadFromMmArchive(samplePath, NULL);
            if (mmSample) {
                font->drums[i]->sound.sample = mmSample;
                patchedCount++;
            }
        }
    }

    // Parse instruments
    for (u32 i = 0; i < instrumentCount && r.pos < r.size; i++) {
        MmBin_ReadU8(&r); // isValidEntry
        MmBin_ReadU8(&r); // loaded
        MmBin_ReadU8(&r); // normalRangeLo
        MmBin_ReadU8(&r); // normalRangeHi
        MmBin_ReadU8(&r); // releaseRate

        u32 envCount = MmBin_ReadU32(&r);
        MmBin_Skip(&r, envCount * 4);

        Instrument* inst = (font->instruments && i < font->numInstruments) ? font->instruments[i] : NULL;

        // Low notes
        if (MmBin_ReadS8(&r)) {
            MmBin_ReadS8(&r); // hasSampleRef
            MmBin_ReadString(&r, samplePath, sizeof(samplePath));
            MmBin_ReadF32(&r); // tuning
            if (samplePath[0] && inst) {
                SoundFontSample* s = (SoundFontSample*)MmAssets_LoadFromMmArchive(samplePath, NULL);
                if (s) {
                    inst->lowNotesSound.sample = s;
                    patchedCount++;
                }
            }
        }

        // Normal notes
        if (MmBin_ReadS8(&r)) {
            MmBin_ReadS8(&r);
            MmBin_ReadString(&r, samplePath, sizeof(samplePath));
            MmBin_ReadF32(&r);
            if (samplePath[0] && inst) {
                SoundFontSample* s = (SoundFontSample*)MmAssets_LoadFromMmArchive(samplePath, NULL);
                if (s) {
                    inst->normalNotesSound.sample = s;
                    patchedCount++;
                }
            }
        }

        // High notes
        if (MmBin_ReadS8(&r)) {
            MmBin_ReadS8(&r);
            MmBin_ReadString(&r, samplePath, sizeof(samplePath));
            MmBin_ReadF32(&r);
            if (samplePath[0] && inst) {
                SoundFontSample* s = (SoundFontSample*)MmAssets_LoadFromMmArchive(samplePath, NULL);
                if (s) {
                    inst->highNotesSound.sample = s;
                    patchedCount++;
                }
            }
        }
    }

    // Parse sound effects
    for (u32 i = 0; i < soundEffectCount && r.pos < r.size; i++) {
        if (MmBin_ReadS8(&r)) {
            MmBin_ReadS8(&r);
            MmBin_ReadString(&r, samplePath, sizeof(samplePath));
            MmBin_ReadF32(&r);
            if (samplePath[0] && font->soundEffects && i < font->numSfx) {
                SoundFontSample* s = (SoundFontSample*)MmAssets_LoadFromMmArchive(samplePath, NULL);
                if (s) {
                    font->soundEffects[i].sample = s;
                    patchedCount++;
                }
            }
        }
    }

    MMSFX_LOG("[MmSfx] PatchSamples DONE: patched %d sample pointers from mm.o2r for %s", patchedCount, fontPath);
}

SoundFont* MmSfx_LoadFont(s32 fontId) {
    if (!sSfxInitialized)
        MmSfxCache_Init();
    if (fontId < 0 || fontId >= 41) // MM has 41 soundfonts (0-40)
        return nullptr;
    if (!MmAssets_IsAvailable())
        return nullptr;

    try {
        MmSfxCacheEntry* cached = MmSfxCache_Find(fontId);
        if (cached && cached->font)
            return cached->font;

        char path[64];
        snprintf(path, sizeof(path), MM_SFX_FONT_PATH_FMT, fontId);

        size_t size = 0;
        void* resource = MmAssets_LoadFromMmArchive(path, &size);
        if (!resource) {
            MMSFX_LOG("[MmSfx] LoadFont FAIL: %s not found in mm.o2r", path);
            return nullptr;
        }

        SoundFont* font = static_cast<SoundFont*>(resource);
        // MM Soundfont_0 = 122 inst, 453 sfx, 16 drums
        // OOT Soundfont_0 = 92 inst, 136 sfx, 4 drums
        const char* source =
            (fontId == 0) ? ((font->numInstruments > 100) ? "MM (CORRECT)" : "OOT (WRONG! archive bypass not working)")
                          : "N/A";
        MMSFX_LOG("[MmSfx] LoadFont(%d) OK: %u instruments, %u sfx, %u drums, instruments=%p — SOURCE: %s", fontId,
                  font->numInstruments, font->numSfx, font->numDrums, (void*)font->instruments, source);

        // CRITICAL: Re-resolve ALL samples from mm.o2r.
        // The factory may have loaded OOT samples due to archive priority and ResourceManager caching.
        // This function re-reads the binary, extracts sample paths, and patches all Sample* pointers.
        MmSfx_PatchFontSamplesFromMmArchive(font, path);

        MmSfxCacheEntry* entry = MmSfxCache_GetFree();
        if (entry) {
            entry->fontId = fontId;
            entry->font = font;
            entry->sizeBytes = size;
        }
        return font;
    } catch (const std::exception& e) {
        MMSFX_LOG("[MmSfx] Exception in LoadFont(%d): %s", fontId, e.what());
    } catch (...) { MMSFX_LOG("[MmSfx] Unknown exception in LoadFont(%d)", fontId); }
    return nullptr;
}

SoundFont* MmSfx_GetFontForSfx(u16 sfxId) {
    s32 bank = MM_SFX_BANK_INDEX(sfxId);
    if (bank < 0 || bank >= 7)
        return nullptr;
    return MmSfx_LoadFont(sMmBankToFontMap[bank]);
}

// =============================================================================
// Direct Audio: ADPCM Decoder
// =============================================================================
// Decodes N64 VADPCM (codec 0) and SMALL_ADPCM (codec 3) to s16 PCM.
// Algorithm: Block-based prediction using codebook (order=2, 8-sample sub-frames).

#define VADPCM_FRAME_ADPCM 9       // codec 0: 1 header + 8 data bytes
#define VADPCM_FRAME_SMALL_ADPCM 5 // codec 3: 1 header + 4 data bytes
#define VADPCM_SAMPLES_PER_FRAME 16

// Decode one ADPCM frame (16 samples)
// Algorithm matches soh/soh/mixer.c aADPCMdecImpl() exactly
static void MmDirectAudio_DecodeFrame(const u8* frame, s32 frameSize, s16* out, const s16* book, s32 order, s16* hist) {
    s32 shift = frame[0] >> 4;
    s32 pred = frame[0] & 0xF;
    const s16* tbl0 = &book[pred * order * 8];     // coefs for prev2
    const s16* tbl1 = &book[pred * order * 8 + 8]; // coefs for prev1
    const u8* data = &frame[1];

    // Extract and scale input nibbles per sub-frame (matching mixer.c)
    for (s32 half = 0; half < 2; half++) {
        s16 ins[8];
        // History: prev1 = most recent output, prev2 = second most recent
        // Matches mixer.c lines 204-205: prev1 = out[-1], prev2 = out[-2]
        s16 prev1 = hist[1];
        s16 prev2 = hist[0];

        if (frameSize == VADPCM_FRAME_SMALL_ADPCM) {
            // codec 3: 2 bits per sample, 2 bytes per sub-frame
            const u8* p = &data[half * 2];
            for (s32 j = 0; j < 2; j++) {
                ins[j * 4] = (s16)(((s32)(p[j] >> 6) << 30) >> 30) << shift;
                ins[j * 4 + 1] = (s16)((((s32)(p[j] >> 4) & 0x3) << 30) >> 30) << shift;
                ins[j * 4 + 2] = (s16)((((s32)(p[j] >> 2) & 0x3) << 30) >> 30) << shift;
                ins[j * 4 + 3] = (s16)((((s32)(p[j]) & 0x3) << 30) >> 30) << shift;
            }
        } else {
            // codec 0: 4 bits per sample, 4 bytes per sub-frame
            const u8* p = &data[half * 4];
            for (s32 j = 0; j < 4; j++) {
                ins[j * 2] = (s16)(((s32)(p[j] >> 4) << 28) >> 28) << shift;
                ins[j * 2 + 1] = (s16)((((s32)(p[j]) & 0xF) << 28) >> 28) << shift;
            }
        }

        // Core prediction loop — matches mixer.c lines 220-227 EXACTLY:
        //   acc = tbl[0][j]*prev2 + tbl[1][j]*prev1 + (ins[j]<<11)
        //   inner: acc += tbl[1][(j-k)-1] * ins[k]   <-- uses ins[], NOT decoded output
        //   *out++ = clamp16(acc >> 11)
        for (s32 j = 0; j < 8; j++) {
            s32 acc = tbl0[j] * prev2 + tbl1[j] * prev1 + ((s32)ins[j] << 11);
            for (s32 k = 0; k < j; k++) {
                acc += tbl1[((j - k) - 1)] * ins[k];
            }
            acc >>= 11;
            if (acc > 32767)
                acc = 32767;
            if (acc < -32768)
                acc = -32768;
            out[half * 8 + j] = (s16)acc;
        }

        // Update history for next sub-frame (mirrors mixer.c out[-1] / out[-2] pointer logic)
        hist[0] = out[half * 8 + 6]; // second most recent
        hist[1] = out[half * 8 + 7]; // most recent
    }
}

// Decode entire ADPCM sample to PCM buffer
static s16* MmDirectAudio_DecodeADPCM(SoundFontSample* sample, u32* outLength) {
    if (!sample || !sample->sampleAddr || sample->size == 0)
        return nullptr;

    s32 frameSize;
    switch (sample->codec) {
        case 0:
            frameSize = VADPCM_FRAME_ADPCM;
            break;
        case 3:
            frameSize = VADPCM_FRAME_SMALL_ADPCM;
            break;
        default:
            MMSFX_LOG("[MmDirectAudio] Unsupported codec %d", sample->codec);
            return nullptr;
    }

    if (!sample->book || !sample->book->book) {
        MMSFX_LOG("[MmDirectAudio] No codebook for sample");
        return nullptr;
    }

    u32 numFrames = sample->size / frameSize;
    u32 totalSamples = numFrames * VADPCM_SAMPLES_PER_FRAME;

    // Limit to loop end if looping
    if (sample->loop && sample->loop->loopEnd > 0 && sample->loop->loopEnd < totalSamples) {
        totalSamples = sample->loop->loopEnd;
        numFrames = (totalSamples + VADPCM_SAMPLES_PER_FRAME - 1) / VADPCM_SAMPLES_PER_FRAME;
    }

    s16* pcm = (s16*)malloc(totalSamples * sizeof(s16));
    if (!pcm)
        return nullptr;

    s16 hist[2] = { 0, 0 };
    const u8* src = (const u8*)sample->sampleAddr;
    s32 order = sample->book->order;
    const s16* book = sample->book->book;

    for (u32 f = 0; f < numFrames; f++) {
        s16 frameBuf[VADPCM_SAMPLES_PER_FRAME];
        MmDirectAudio_DecodeFrame(&src[f * frameSize], frameSize, frameBuf, book, order, hist);

        u32 dstOffset = f * VADPCM_SAMPLES_PER_FRAME;
        u32 count = VADPCM_SAMPLES_PER_FRAME;
        if (dstOffset + count > totalSamples) {
            count = totalSamples - dstOffset;
        }
        memcpy(&pcm[dstOffset], frameBuf, count * sizeof(s16));
    }

    *outLength = totalSamples;
    return pcm;
}

// =============================================================================
// Direct Audio: Playing Sound List + Mixer
// =============================================================================

#define MM_DIRECT_MAX_SOUNDS 16
#define MM_GAKKI_SFXID 0x5800 // Dedicated sfxId for gakki instrument notes (stop/replace management)

// ADSR envelope phases (matches N64 audio synthesis)
#define ADSR_PHASE_ATTACK 0
#define ADSR_PHASE_DECAY 1
#define ADSR_PHASE_SUSTAIN 2
#define ADSR_PHASE_RELEASE 3

typedef struct {
    s16* pcmData;       // Decoded PCM buffer (allocated, must be freed)
    u32 pcmLength;      // Total samples in buffer
    f32 pcmPosition;    // Current fractional playback position
    f32 advance;        // Samples to advance per output sample (tuning * freqScale)
    f32 volume;         // Volume [0..1] (base volume before envelope)
    f32 pan;            // Pan [0=left, 0.5=center, 1=right]
    u32 loopStart;      // Loop start sample (from sample->loop)
    u32 loopEnd;        // Loop end sample (0 = no loop)
    u32 lifeSamples;    // Output samples elapsed since start
    u32 maxLifeSamples; // Maximum output samples before auto-stop (0 = no limit)
    f32 vibratoPhase;   // Vibrato LFO phase [0..1]
    f32 vibratoRate;    // Vibrato LFO rate (Hz), 0 = no vibrato
    f32 vibratoDepth;   // Vibrato pitch modulation depth [0..1]
    // Portamento (pitch sweep from startAdvance to target advance over portaDuration samples)
    f32 portaStartAdv; // Starting advance rate (0 = no portamento)
    f32 portaEndAdv;   // Target advance rate
    f32 portaProgress; // Current progress [0..1], 1 = reached target
    f32 portaRate;     // Progress increment per sample (1/portaDurationSamples)
    // ADSR envelope (replicates N64 sequencer envelope shaping)
    f32 envVolume;        // Current envelope amplitude [0..1]
    f32 envAttackRate;    // Per-sample attack increment (0→1)
    f32 envDecayRate;     // Per-sample decay decrement (1→sustain)
    f32 envSustainLevel;  // Sustain hold level [0..1]
    f32 envReleaseRate;   // Per-sample release decrement (sustain→0)
    u32 envReleaseAt;     // Output sample count at which release begins (0 = at end of PCM)
    u8 envPhase;          // Current ADSR phase
    u16 mmSfxId;          // MM SFX ID for stop/identify
    u8 active;            // 1=playing, 0=free
    u8 ownsPcm;           // 1=owns pcmData (must free on reuse), 0=cached WAV (don't free)
    u8 isContinuous;      // 1=continuous sound (needs per-frame refresh), 0=one-shot
    u32 lastRefreshFrame; // Frame counter when this sound was last triggered/refreshed
} MmPlayingSound;

static u32 sMmAudioFrame = 0; // Incremented each mixer call (~every 50ms)

static MmPlayingSound sPlayingSounds[MM_DIRECT_MAX_SOUNDS];

// SFX IDs that are truly continuous — they loop until explicitly stopped via MmSfx_Stop.
// Everything else is one-shot: plays through once (ignoring sustain loops from sample metadata).
// In N64, sustain loops (count=-1) are held by ADSR envelopes until note-off from the sequencer.
// We don't have ADSR or note-off, so we must whitelist the few sounds that genuinely loop.
static const u16 sContinuousSfxIds[] = {
    0x0990, // GORON_ROLL (rolling sound, stopped when ball ends)
    0x08EB, // GORON_BALL_CHARGE (charging up, stopped when released)
    0x09A1, // DEKUNUTS_BUBLE_BREATH (bubble charging, stopped when fired)
    0x09AD, // GORON_SLIP (slipping sound, stopped when grounded)
    0x08ED, // ZORA_SWIM_LV (level swim sound)
    0x08D0, // SLIP_LEVEL (slipping)
    0x5800, // GAKKI instrument notes (stopped on button release)
};
static const s32 sContinuousSfxIdsSize = sizeof(sContinuousSfxIds) / sizeof(sContinuousSfxIds[0]);

static bool MmDirectAudio_IsContinuous(u16 mmSfxId) {
    for (s32 i = 0; i < sContinuousSfxIdsSize; i++) {
        if (sContinuousSfxIds[i] == mmSfxId)
            return true;
    }
    return false;
}

// Configure ADSR envelope for a playing sound.
// Simple anti-click envelope: quick attack, full sustain, smooth release.
// NOTE: MM instrument envelope data from mm.o2r is byte-swap corrupted
// (AudioSoundFontFactory applies BE16SWAP but mm.o2r stores LE data from 2Ship).
// All instruments show sus=0.28 instead of 1.0. Until we fix the byte-swap,
// we use this simple default that sounds correct.
static void MmDirectAudio_SetEnvelope(MmPlayingSound* snd, bool isContinuous) {
    snd->envVolume = 0.0f;
    snd->envPhase = ADSR_PHASE_ATTACK;
    snd->envAttackRate = 1.0f / 64.0f;   // 2ms attack (prevents click)
    snd->envDecayRate = 0.0f;            // No decay (instant to sustain)
    snd->envSustainLevel = 1.0f;         // Full sustain
    snd->envReleaseRate = 1.0f / 320.0f; // 10ms release (prevents click)
    snd->envReleaseAt = 0;

    if (isContinuous) {
        return;
    }

    // One-shot sounds: auto-release near end for smooth fade-out
    f32 advance = snd->advance;
    if (advance <= 0.0f)
        advance = 1.0f;
    u32 playbackSamples = (u32)(snd->pcmLength / advance);
    if (playbackSamples > 320) {
        snd->envReleaseAt = playbackSamples - 320; // Start release 10ms before end
    }
}

// =============================================================================
// SFX → Instrument Mapping Table (derived from seq_0.prg.seq analysis)
// =============================================================================
// In MM, SFX IDs do NOT index directly into soundEffects[] or drums[].
// They go through the SFX sequence (seq_0) which selects specific instruments
// from Soundfont_0 and plays them at specific pitches.
//
// This table maps each known Goron SFX to its primary instrument and note,
// giving us the correct sample with correct pitch - matching MM 1:1.

typedef struct {
    u16 sfxId;        // MM SFX ID (with SFX_FLAG)
    u8 instrumentIdx; // Index into font->instruments[] (Soundfont_0)
    u8 midiNote;      // MIDI note number for pitch calculation (target note for portamento)
    s8 transpose;     // Layer transpose (added to midiNote for pitch calc, 0=none)
    u8 portaNote;     // Portamento start note (0=no portamento, sweeps from here to midiNote+transpose)
    u8 portaSpeed;    // Portamento speed (0=instant, 255=slow sweep). Duration in frames.
} MmSfxInstrMapEntry;

